pragma solidity ^0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721.sol";

contract MintingAndTreasureChestManagement is ReentrancyGuard {
    enum State { Presale, PublicSale, Minting }
    State public currentState;
    uint256 public presalePrice;
    uint256 public maxPublicPrice;
    uint256 public minPublicPrice;
    uint256 public publicSaleStart;
    uint256 public maxSupply;
    uint256 public totalMinted;
    mapping(address => bool) public whitelist;
    address public treasuryAddress;
    address public treasureChestContract;

    event Minted(address indexed account, uint256 tokenId);
    event WhitelistUpdated(address indexed account, bool status);
    event SaleStateChanged(State newState);

    modifier onlyWhitelisted() {
        require(whitelist[msg.sender], "Not whitelisted");
        _;
    }

    modifier onlyDuringPresale() {
        require(currentState == State.Presale, "Not in presale state");
        _;
    }

    modifier onlyDuringPublicSale() {
        require(currentState == State.PublicSale, "Not in public sale state");
        _;
    }

    constructor(uint256 _presalePrice, uint256 _maxPublicPrice, uint256 _minPublicPrice, uint256 _maxSupply, address _treasuryAddress) {
        presalePrice = _presalePrice;
        maxPublicPrice = _maxPublicPrice;
        minPublicPrice = _minPublicPrice;
        maxSupply = _maxSupply;
        publicSaleStart = block.timestamp + 5 days; // Public sale starts 5 days after deployment
        currentState = State.Presale;
        treasuryAddress = _treasuryAddress;
    }

    function setContracts(address _treasureChestContract) external {
        require(msg.sender == treasuryAddress, "Unauthorized");
        treasureChestContract = _treasureChestContract;
    }

    function setPublicSaleStart(uint256 _publicSaleStart) external {
        require(msg.sender == treasuryAddress, "Unauthorized");
        publicSaleStart = _publicSaleStart;
    }

    function addToWhitelist(address[] memory accounts) external onlyDuringPresale {
        require(msg.sender == treasuryAddress, "Unauthorized");
        for (uint256 i = 0; i < accounts.length; i++) {
            whitelist[accounts[i]] = true;
            emit WhitelistUpdated(accounts[i], true);
        }
    }

    function startPublicSale() external {
        require(msg.sender == treasuryAddress, "Unauthorized");
        require(block.timestamp >= publicSaleStart, "Public sale has not started yet");
        currentState = State.PublicSale;
        emit SaleStateChanged(currentState);
    }

    function mint() external payable nonReentrant {
        require(totalMinted < maxSupply, "Max supply reached");
        if (currentState == State.Presale) {
            require(whitelist[msg.sender], "Not whitelisted");
            require(msg.value >= presalePrice, "Insufficient funds");
        } else if (currentState == State.PublicSale) {
            require(block.timestamp >= publicSaleStart, "Public sale has not started yet");
            uint256 currentPrice = calculateCurrentPrice();
            require(msg.value >= currentPrice, "Insufficient funds");
        }
        totalMinted++;
        emit Minted(msg.sender, totalMinted);
    }

    function calculateCurrentPrice() internal view returns (uint256) {
        uint256 timePassed = block.timestamp - publicSaleStart;
        uint256 priceDecay = (maxPublicPrice - minPublicPrice) * timePassed / (30 days); // Price decays linearly over 30 days
        return max(maxPublicPrice - priceDecay, minPublicPrice);
    }

    function sacrifice(uint256 tokenId) external nonReentrant {
        require(IERC721(treasureChestContract).ownerOf(tokenId) == msg.sender, "Not owner of treasure chest");
        IERC721(treasureChestContract).safeTransferFrom(msg.sender, address(this), tokenId);
        // Logic for sacrificing tokens goes here
    }

    receive() external payable {}

    function max(uint256 a, uint256 b) internal pure returns (uint256) {
        return a >= b ? a : b;
    }

    function setState(State newState) external {
        require(msg.sender == treasuryAddress, "Unauthorized");
        require(newState != currentState, "Invalid state transition");
        currentState = newState;
        emit SaleStateChanged(newState);
    }
}
